/**
 * @name Taint from HTTP request to ResourceHelper.resolveMandatoryResourceAsInputStream
 * @description HTTP request data flowing to ResourceHelper which supports file: protocol prefix
 *              allowing filesystem path traversal outside classpath
 * @kind path-problem
 * @problem.severity error
 * @id java/http-to-resource-helper
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-073
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module HttpToResourceHelperConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // ResourceHelper.resolveMandatoryResourceAsInputStream(camelContext, uri)
    exists(MethodCall mc |
      mc.getMethod().getDeclaringType().hasQualifiedName("org.apache.camel.util", "ResourceHelper") and
      (
        mc.getMethod().hasName("resolveMandatoryResourceAsInputStream") or
        mc.getMethod().hasName("resolveResourceAsInputStream")
      ) and
      sink.asExpr() = mc.getArgument(1) // The URI argument (second arg)
    )
  }
}

module HttpToResourceHelperFlow = TaintTracking::Global<HttpToResourceHelperConfig>;
import HttpToResourceHelperFlow::PathGraph

from HttpToResourceHelperFlow::PathNode source, HttpToResourceHelperFlow::PathNode sink
where HttpToResourceHelperFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "HTTP input $@ flows to ResourceHelper.resolveMandatoryResourceAsInputStream - 'file:' prefix injection could allow filesystem traversal", source.getNode(), "HTTP input"

/**
 * @name Zip Slip - ZipEntry/TarEntry getName() flowing to File in Camel archive data formats
 * @description Archive entry name flows to File constructor without canonicalization or traversal check
 * @kind path-problem
 * @problem.severity error
 * @id java/camel-zip-slip-confirmed
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking

module ZipSlipConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      (
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.util.zip", "ZipEntry") or
        mc.getMethod().getDeclaringType().hasName("ZipArchiveEntry") or
        mc.getMethod().getDeclaringType().hasName("TarArchiveEntry")
      ) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // File constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // Paths.get  
    exists(MethodCall mc |
      mc.getMethod().hasName("get") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module ZipSlipFlow = TaintTracking::Global<ZipSlipConfig>;
import ZipSlipFlow::PathGraph

from ZipSlipFlow::PathNode source, ZipSlipFlow::PathNode sink
where ZipSlipFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Zip Slip: archive entry $@ flows to file path construction without traversal validation", source.getNode(), "entry name"
